  selectFeature,
  (feature) => feature.someValue * 2
);
```

To handle errors in an NgRx effect without crashing the effect stream, use the `catchError` operator within the `switchMap`. This allows you to catch the error and return a new observable that dispatches a failure action. Here's a concise example:

```typescript
import { Actions, ofType, createEffect } from '@ngrx/effects';
import { switchMap, catchError } from 'rxjs/operators';
import { of } from 'rxjs';
import { SomeAction } from './actions';
import { ApiService } from './api.service';

export class MyEffects {
  constructor(private actions$: Actions, private apiService: ApiService) {}

  loadData$ = createEffect(() =>
    this.actions$.pipe(
      ofType(SomeAction.load),
      switchMap(() =>
        this.apiService.getData().pipe(
          map(data => SomeAction.loadSuccess({ data })),
          catchError(error => of(SomeAction.loadFailure({ error })))
        )
      )
    )
  );
}
```

In this example, if the API call fails, it dispatches `loadFailure` with the error, ensuring the effect stream remains active.

